mapper.update:
UPDATE article
title = #{title}, content = #{content}, cover_img = #{coverImg}, excerpt = #{excerpt}, state = #{state}, category_id = #{categoryId}, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT * FROM article


        create_user = #{userId}


        AND category_id = #{categoryId}


        AND state = #{state}


ORDER BY create_time DESC

SELECT a.id, a.title, a.cover_img, a.excerpt, a.state, a.category_id, a.create_user, a.create_time, a.update_time, a.view_count, a.like_count, a.comment_count, a.favorite_count, a.share_count, u.nickname AS author_name, u.user_pic AS author_avatar, c.category_name, t.id AS tag_id, t.tag_name AS tag_name, t.tag_color AS tag_color FROM article a LEFT JOIN user u ON a.create_user = u.id LEFT JOIN category c ON a.category_id = c.id LEFT JOIN article_tag at ON a.id = at.article_id LEFT JOIN tag t ON at.tag_id = t.id
a.create_user = #{userId}
AND a.category_id = #{categoryId}
AND a.state = #{state}
ORDER BY a.create_time DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM article


        create_user = #{userId}


        AND category_id = #{categoryId}


        AND state = #{state}

SELECT a.id, a.title, a.cover_img, a.excerpt, a.state, a.category_id, a.create_user, a.create_time, a.update_time, a.view_count, a.like_count, a.comment_count, a.favorite_count, a.share_count, u.nickname AS author_name, u.user_pic AS author_avatar, c.category_name, t.id AS tag_id, t.tag_name AS tag_name, t.tag_color AS tag_color FROM article a LEFT JOIN user u ON a.create_user = u.id LEFT JOIN category c ON a.category_id = c.id LEFT JOIN article_tag at ON a.id = at.article_id LEFT JOIN tag t ON at.tag_id = t.id WHERE a.state = #{state}
ORDER BY a.hot_score DESC, a.create_time DESC
ORDER BY (a.like_count * 2 + a.favorite_count * 3 + a.comment_count * 1.5) / POWER(GREATEST(TIMESTAMPDIFF(HOUR, a.create_time, NOW()), 1) + 1, 1.5) DESC, a.create_time DESC
ORDER BY a.create_time DESC
LIMIT #{offset}, #{pageSize}

